    24→
    25→@Service
    26→public class ChatService {
    27→
    28→    private static final List<String> REASONING_KEYS =
    29→            List.of("thinking", "reasoningContent", "reasoning_content", "reasoning");
    30→
    31→    private final ProviderConfigRepository configRepository;
    32→    private final ChatModelFactory chatModelFactory;
    33→    private final ChatToolCallbacksService toolCallbacksService;
    34→    private final McpService mcpService;
    35→    private final ConversationRepository conversationRepository;
    36→    private final boolean delegationEnabled;
    37→    private final boolean manualApprove;
    38→    private final int toolExecutionTimeoutSeconds;
    39→    private final ToolApprovalService toolApprovalService;
    40→
    41→    public ChatService(ProviderConfigRepository configRepository,
    42→                       ChatModelFactory chatModelFactory,
    43→                       ChatToolCallbacksService toolCallbacksService,
    44→                       McpService mcpService,
    45→                       ConversationRepository conversationRepository,
    46→                       ToolApprovalService toolApprovalService,
    47→                       @Value("${aidaemon.delegation-enabled:false}") boolean delegationEnabled,
    48→                       @Value("${aidaemon.manual-approve:false}") boolean manualApprove,
    49→                       @Value("${aidaemon.tool-execution-timeout-seconds:300}") int toolExecutionTimeoutSeconds) {
    50→        this.configRepository = configRepository;
    51→        this.chatModelFactory = chatModelFactory;
    52→        this.toolCallbacksService = toolCallbacksService;
    53→        this.mcpService = mcpService;
    54→        this.conversationRepository = conversationRepository;
    55→        this.toolApprovalService = toolApprovalService;
    56→        this.delegationEnabled = delegationEnabled;
    57→        this.manualApprove = manualApprove;
    58→        this.toolExecutionTimeoutSeconds = toolExecutionTimeoutSeconds;
    59→    }
    60→
    61→    public ChatResult streamAndCollect(String providerId, List<Message> contextMessages, StreamRequestMetadata meta) {
    62→        var resultRef = new AtomicReference<ChatResult>();
    63→        stream(providerId, contextMessages, meta, resultRef::set).blockLast();
    64→        return resultRef.get();
    65→    }
    66→
    67→    public Flux<StreamChunk> stream(String providerId, List<Message> contextMessages, StreamRequestMetadata meta,
    68→                                   Consumer<ChatResult> onComplete) {
    69→        var config = configRepository.findById(providerId)
    70→                .orElseThrow(() -> new IllegalArgumentException("Provider not found: " + providerId));
    71→
    72→        final var toolLog = new ArrayList<ChatMessage>();
    73→        var sink = Sinks.many().unicast().<StreamChunk>onBackpressureBuffer();
    74→        var onToolChunk = (Consumer<StreamChunk>) c -> sink.tryEmitNext(c);
    75→        var approvalServiceForTools = manualApprove ? toolApprovalService : null;
    76→        var execTimeout = manualApprove ? toolExecutionTimeoutSeconds : 0;
    77→        var loggingTools = new ArrayList<ToolCallback>();
    78→        for (var t : toolCallbacksService.buildToolCallbacks(meta, config.id())) {
    79→            loggingTools.add(new LoggingToolCallback(t, toolLog, null, onToolChunk, approvalServiceForTools, execTimeout));
    80→        }
    81→        mcpService.getToolCallbacksByServer().forEach((serverName, callbacks) ->
    82→                callbacks.forEach(t -> loggingTools.add(new LoggingToolCallback(t, toolLog, serverName, onToolChunk, approvalServiceForTools, execTimeout))));
    83→
    84→        final DelegationTools delegationTools = (delegationEnabled && meta.conversationId() != null)
    85→                ? new DelegationTools(conversationRepository, meta.conversationId(), providerId, meta.botName())
    86→                : null;
    87→        if (delegationTools != null) {
    88→            for (var t : org.springframework.ai.support.ToolCallbacks.from(delegationTools)) {
    89→                loggingTools.add(new LoggingToolCallback(t, toolLog, null, onToolChunk, approvalServiceForTools, execTimeout));
    90→            }
    91→        }
    92→
    93→        var chatModel = chatModelFactory.create(config, loggingTools);
    94→        var promptOptions = chatModelFactory.promptOptions(config, loggingTools);
    95→        if (!(chatModel instanceof StreamingChatModel streamingModel)) {
    96→            var error = "Provider does not support streaming; only streaming models are supported.";
    97→            onComplete.accept(new ChatResult("[Error] " + error, List.of()));
    98→            return Flux.just(new StreamChunk(StreamChunk.TYPE_ANSWER, "[Error] " + error));
    99→        }
   100→
   101→        final StringBuilder contentAccum = new StringBuilder();
   102→        final StringBuilder reasoningAccum = new StringBuilder();
   103→        final var orderedChunks = new ArrayList<StreamChunk>();
   104→        var prompt = promptOptions != null ? new Prompt(contextMessages, promptOptions) : new Prompt(contextMessages);
   105→
   106→        var contentStream = streamingModel.stream(prompt)
   107→                .flatMap(response -> {
   108→                    var c = toStreamChunk(response);
   109→                    return c != null ? Flux.just(c) : Flux.empty();
   110→                })
   111→                .doOnNext(c -> {
   112→                    if (StreamChunk.TYPE_REASONING.equals(c.type())) {
   113→                        reasoningAccum.append(c.content());
   114→                    } else if (StreamChunk.TYPE_ANSWER.equals(c.type())) {
   115→                        contentAccum.append(c.content());
   116→                    }
   117→                })
   118→                .doOnComplete(() -> sink.emitComplete(Sinks.EmitFailureHandler.FAIL_FAST))
   119→                .doOnError(e -> sink.emitComplete(Sinks.EmitFailureHandler.FAIL_FAST));
   120→
   121→        var merged = Flux.merge(contentStream, sink.asFlux())
   122→                .doOnNext(c -> {
   123→                    if (StreamChunk.TYPE_ANSWER.equals(c.type()) || StreamChunk.TYPE_TOOL.equals(c.type())) {
   124→                        orderedChunks.add(c);
   125→                    }
   126→                });
   127→        return merged
   128→                .doOnComplete(() -> {
   129→                    var pendingIds = delegationTools != null
   130→                            ? delegationTools.getPendingSubConversationIds() : List.<String>of();
   131→                    var parts = coalesceOrderedChunks(orderedChunks);
   132→                    var reasoning = reasoningAccum.isEmpty() ? null : reasoningAccum.toString();
   133→                    var partsWithReasoning = new ArrayList<StreamChunk>();
   134→                    if (reasoning != null && !reasoning.isEmpty()) {
   135→                        partsWithReasoning.add(new StreamChunk(StreamChunk.TYPE_REASONING, reasoning));
