    26→
    27→    public ConversationRepository(
    28→            @Value("${aidaemon.config-dir:${user.home}/.aidaemon}") String configDir) {
    29→        this.conversationsDir = Path.of(configDir, "conversations");
    30→    }
    31→
    32→    @PostConstruct
    33→    void load() throws IOException {
    34→        Files.createDirectories(conversationsDir);
    35→        try (var stream = Files.list(conversationsDir)) {
    36→            stream.filter(Files::isDirectory)
    37→                    .forEach(dir -> {
    38→                        var conversationFile = dir.resolve("conversation.json");
    39→                        if (Files.exists(conversationFile)) {
    40→                            try {
    41→                                var conv = objectMapper.readValue(conversationFile.toFile(), Conversation.class);
    42→                                conversations.put(conv.id(), conv);
    43→                            } catch (IOException e) {
    44→                                throw new UncheckedIOException(e);
    45→                            }
    46→                        }
    47→                    });
    48→        }
    49→    }
