    61→    public List<Conversation> findByParticipant(String participant) {
    62→        if (participant == null) return List.of();
    63→        return conversations.values().stream()
    64→                .filter(c -> c.isDirect() && (participant.equals(c.participant1()) || participant.equals(c.participant2())))
    65→                .toList();
