    67→
    68→    public List<Conversation> findAllForParticipant(String participant) {
    69→        if (participant == null) return findAll();
    70→        return conversations.values().stream()
    71→                .filter(c -> !c.isDirect() || participant.equals(c.participant1()) || participant.equals(c.participant2()))
    72→                .toList();
