    94→                                try {
    95→                                    Files.deleteIfExists(path);
    96→                                } catch (IOException e) {
    97→                                    throw new UncheckedIOException(e);
    98→                                }
    99→                            });
   100→                }
   101→            }
   102→        } catch (IOException e) {
   103→            throw new UncheckedIOException(e);
   104→        }
   105→        return true;
