    91→export function sendMessageStream(
    92→  conversationId: string,
    93→  message: string,
    94→  onChunk: (chunk: StreamChunk) => void,
    95→  onDone: () => void,
    96→  onError: (err: unknown) => void,
    97→  fileIds?: string[]
    98→): void {
    99→  fetch(`/api/conversations/${conversationId}/messages/stream`, {
   100→    method: 'POST',
   101→    headers: JSON_HEADERS,
   102→    body: JSON.stringify({ message, fileIds: fileIds ?? [] }),
   103→  })
   104→    .then(async (res) => {
   105→      if (!res.ok || !res.body) {
   106→        onError(new Error(res.statusText));
   107→        return;
   108→      }
   109→      const reader = res.body.getReader();
   110→      const decoder = new TextDecoder();
   111→      let buffer = '';
   112→      while (true) {
   113→        const { done, value } = await reader.read();
   114→        if (done) break;
   115→        buffer += decoder.decode(value, { stream: true });
   116→        const events = buffer.split('\n\n');
   117→        buffer = events.pop() ?? '';
   118→        for (const event of events) {
   119→          const dataLine = event.split('\n').find((l) => l.startsWith('data:'));
   120→          if (dataLine) {
   121→            const data = dataLine.slice(5).trim();
   122→            if (data) {
   123→              try {
   124→                onChunk(JSON.parse(data) as StreamChunk);
   125→              } catch {
   126→                // skip non-JSON
   127→              }
   128→            }
   129→          }
   130→        }
   131→      }
   132→      if (buffer.trim()) {
   133→        const dataLine = buffer.split('\n').find((l) => l.startsWith('data:'));
   134→        if (dataLine) {
   135→          const data = dataLine.slice(5).trim();
   136→          if (data) {
   137→            try {
   138→              onChunk(JSON.parse(data) as StreamChunk);
   139→            } catch {
   140→              // skip
   141→            }
   142→          }
   143→        }
   144→      }
   145→      onDone();
   146→    })
   147→    .catch(onError);
   148→}
