   303→function parseStructuredContent(content: string): StreamPart[] | null {
   304→  if (!content || typeof content !== 'string') return null;
   305→  const trimmed = content.trim();
   306→  if (!trimmed.startsWith('{"parts":')) return null;
   307→  try {
   308→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   309→    if (!Array.isArray(data.parts)) return null;
   310→    const parts: StreamPart[] = data.parts
   311→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   312→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   313→    return parts.length > 0 ? parts : null;
   314→  } catch {
   315→    return null;
   316→  }
   317→}
   318→
   319→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   320→  if (!hideToolsAndThinking) return parts;
   321→  const answerParts = parts.filter((p) => p.type === 'answer');
   322→  return answerParts.map((p, i, arr) => ({
   323→    ...p,
   324→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   325→  }));
   326→}
   327→
   328→function getDisplayMessages(
   329→  messages: ChatMessage[],
   330→  hideToolsAndThinking: boolean,
   331→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   332→): DisplayMessage[] {
   333→  let list: DisplayMessage[] = messages.map((msg) => {
   334→    if (msg.role === 'assistant') {
   335→      const parts = parseStructuredContent(msg.content);
   336→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   337→    }
   338→    return msg;
   339→  });
   340→  if (lastStreamedContent && list.length > 0) {
   341→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   342→    const afterLastUser = list.slice(lastUserIdx + 1);
   343→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   344→      const parts: StreamPart[] = lastStreamedContent.reasoning
   345→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   346→        : lastStreamedContent.parts;
   347→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   348→    }
   349→  }
   350→  return list;
   351→}
