   358→function editablePlainText(el: HTMLDivElement): string {
   359→  let text = '';
   360→  el.childNodes.forEach((n) => {
   361→    if (n.nodeType === Node.TEXT_NODE) text += n.textContent ?? '';
   362→  });
   363→  return text;
   364→}
