   373→type UserPart = { type: 'text'; content: string } | { type: 'file'; id: string; name: string; mimeType: string };
   374→
   375→function parseUserParts(content: string): UserPart[] | null {
   376→  if (!content || !content.trim().startsWith('{"user_parts":')) return null;
   377→  try {
   378→    const data = JSON.parse(content) as { user_parts?: Array<{ type: string; content?: string; id?: string; name?: string; mimeType?: string }> };
   379→    if (!Array.isArray(data.user_parts)) return null;
   380→    return data.user_parts
   381→      .filter((p) => p.type === 'text' || p.type === 'file')
   382→      .map((p) =>
   383→        p.type === 'file'
   384→          ? { type: 'file' as const, id: p.id ?? '', name: p.name ?? '', mimeType: p.mimeType ?? '' }
   385→          : { type: 'text' as const, content: p.content ?? '' }
   386→      );
   387→  } catch {
   388→    return null;
   389→  }
   390→}
   391→
   392→function extractEditableContent(el?: HTMLDivElement | null): { parts: UserPart[]; files: FileAttachment[] } {
   393→  if (!el) return { parts: [], files: [] };
   394→  const rawParts: UserPart[] = [];
   395→  const files: FileAttachment[] = [];
   396→  el.childNodes.forEach((n) => {
   397→    if (n.nodeType === Node.TEXT_NODE) {
   398→      const text = n.textContent ?? '';
   399→      if (text) {
   400→        const last = rawParts[rawParts.length - 1];
   401→        if (last?.type === 'text') {
   402→          (last as { type: 'text'; content: string }).content += text;
   403→        } else {
   404→          rawParts.push({ type: 'text', content: text });
   405→        }
   406→      }
   407→    } else if (n.nodeType === Node.ELEMENT_NODE) {
   408→      const span = n as HTMLElement;
   409→      if (span.dataset.fileId) {
   410→        const file: FileAttachment = { id: span.dataset.fileId, name: span.dataset.fileName ?? '', mimeType: span.dataset.fileMimeType ?? '' };
   411→        rawParts.push({ type: 'file', id: file.id, name: file.name, mimeType: file.mimeType });
   412→        files.push(file);
   413→      }
   414→    }
   415→  });
   416→  // Trim leading/trailing whitespace from boundary text parts
   417→  if (rawParts.length > 0 && rawParts[0].type === 'text') {
   418→    (rawParts[0] as { type: 'text'; content: string }).content = (rawParts[0] as { type: 'text'; content: string }).content.trimStart();
   419→  }
   420→  const lastPart = rawParts[rawParts.length - 1];
   421→  if (lastPart?.type === 'text') {
   422→    (lastPart as { type: 'text'; content: string }).content = (lastPart as { type: 'text'; content: string }).content.trimEnd();
   423→  }
   424→  const parts = rawParts.filter((p) => p.type === 'file' || (p as { type: 'text'; content: string }).content.length > 0);
   425→  return { parts, files };
   426→}
   427→
   428→function escapeHtml(s: string): string {
   429→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
   430→}
   431→
   432→export default function ChatWindow({
   433→  headerTitle,
   434→  conversation,
   435→  providers,
   436→  bots,
   437→  sending,
   438→  streaming,
   439→  lastStreamedContent,
   440→  inputDraft,
   441→  onInputDraftChange,
   442→  onSend,
   443→  onUpdateProvider,
   444→  onUpdateBot,
   445→  pendingApprovals,
   446→  onApproveTool,
   447→  onRejectTool,
   448→}: ChatWindowProps) {
   449→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   450→  const [isRecording, setIsRecording] = useState(false);
   451→  const [speakingIdx, setSpeakingIdx] = useState<number | null>(null);
   452→  const [uploadingFile, setUploadingFile] = useState(false);
   453→  const [hasContent, setHasContent] = useState(false);
   454→  const messagesRef = useRef<HTMLDivElement>(null);
   455→  const topRef = useRef<HTMLDivElement>(null);
   456→  const bottomRef = useRef<HTMLDivElement>(null);
   457→  const recognitionRef = useRef<any>(null);
   458→  const fileInputRef = useRef<HTMLInputElement>(null);
   459→  const editableRef = useRef<HTMLDivElement>(null);
   460→  // true while we are the source of an inputDraft change — prevents syncing back
   461→  const isInternalChangeRef = useRef(false);
   462→
   463→  // Stop recording and TTS when conversation changes
   464→  useEffect(() => {
   465→    recognitionRef.current?.stop();
   466→    setIsRecording(false);
   467→    speechSynthesis.cancel();
   468→    setSpeakingIdx(null);
   469→  }, [conversation?.id]);
   470→
   471→  // Sync external inputDraft changes (e.g. speech recognition) into the editable div
   472→  // while preserving file chips already embedded in the div.
   473→  useLayoutEffect(() => {
   474→    if (isInternalChangeRef.current) {
   475→      isInternalChangeRef.current = false;
   476→      return;
   477→    }
   478→    const el = editableRef.current;
   479→    if (!el) return;
   480→    // Collect existing chip nodes to re-append after text
   481→    const chips = Array.from(el.childNodes).filter(
   482→      (n) => n.nodeType === Node.ELEMENT_NODE && (n as HTMLElement).dataset.fileId
   483→    );
   484→    el.innerHTML = '';
   485→    if (inputDraft) el.appendChild(document.createTextNode(inputDraft));
   486→    chips.forEach((c) => el.appendChild(c));
   487→    setHasContent(editableHasContent(el));
   488→  }, [inputDraft]);
   489→
   490→  const visibleMessages = conversation
   491→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   492→    : [];
   493→
   494→  useEffect(() => {
   495→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   496→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   497→
   498→  const hasProvider = Boolean(conversation?.providerId);
   499→  const isDirectChat = Boolean(
   500→    conversation?.participant1 != null && conversation?.participant2 != null
   501→  );
   502→
   503→  const handleSend = () => {
   504→    if (sending || !hasProvider) return;
   505→    const { parts, files } = extractEditableContent(editableRef.current);
   506→    if (parts.length === 0) return;
   507→    const el = editableRef.current;
   508→    if (el) {
   509→      el.innerHTML = '';
   510→      isInternalChangeRef.current = true;
   511→      onInputDraftChange('');
   512→      setHasContent(false);
   513→    }
   514→    const message = files.length > 0
   515→      ? JSON.stringify({ user_parts: parts })
   516→      : ((parts[0] as { type: 'text'; content: string })?.content ?? '');
   517→    onSend(message, files.length > 0 ? files : undefined);
   518→  };
   519→
   520→  const handleEditableInput = () => {
   521→    const el = editableRef.current;
   522→    if (!el) return;
   523→    isInternalChangeRef.current = true;
   524→    onInputDraftChange(editablePlainText(el));
   525→    setHasContent(editableHasContent(el));
   526→  };
   527→
   528→  const handleEditableClick = (e: React.MouseEvent<HTMLDivElement>) => {
   529→    const target = e.target as HTMLElement;
   530→    if (target.dataset.removeChipId) {
   531→      const chip = target.closest('[data-file-id]') as HTMLElement | null;
   532→      chip?.remove();
   533→      isInternalChangeRef.current = true;
   534→      const el = editableRef.current;
   535→      if (el) {
   536→        onInputDraftChange(editablePlainText(el));
   537→        setHasContent(editableHasContent(el));
   538→      }
   539→    }
   540→  };
   541→
   542→  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
   543→    const files = Array.from(e.target.files ?? []);
   544→    if (files.length === 0) return;
   545→    e.target.value = '';
   546→    setUploadingFile(true);
   547→    try {
   548→      const uploaded = await Promise.all(files.map((f) => api.uploadFile(conversation!.id, f)));
   549→      uploaded.forEach(insertFileChip);
   550→    } catch {
   551→      // ignore upload errors silently
   552→    } finally {
   553→      setUploadingFile(false);
   554→    }
   555→  };
   556→
   557→  const insertFileChip = (attachment: FileAttachment) => {
   558→    const el = editableRef.current;
   559→    if (!el) return;
   560→    el.focus();
   561→    const chip = document.createElement('span');
   562→    chip.contentEditable = 'false';
   563→    chip.dataset.fileId = attachment.id;
   564→    chip.dataset.fileName = attachment.name;
   565→    chip.dataset.fileMimeType = attachment.mimeType;
   566→    chip.className = FILE_CHIP_CLASS;
   567→    chip.title = attachment.name;
   568→    chip.innerHTML =
   569→      `<svg width="11" height="11" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0"><path d="M7 1H3a1 1 0 00-1 1v8a1 1 0 001 1h6a1 1 0 001-1V4L7 1z"/><path d="M7 1v3h3"/></svg>` +
   570→      `<span style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(attachment.name)}</span>` +
   571→      `<span data-remove-chip-id="${attachment.id}" style="cursor:pointer;margin-left:2px;opacity:0.7;flex-shrink:0" title="Remove">✕</span>`;
   572→
   573→    const sel = window.getSelection();
   574→    if (sel && sel.rangeCount > 0 && el.contains(sel.getRangeAt(0).commonAncestorContainer)) {
   575→      const range = sel.getRangeAt(0);
   576→      range.deleteContents();
   577→      range.insertNode(chip);
   578→      range.setStartAfter(chip);
   579→      range.collapse(true);
   580→      sel.removeAllRanges();
   581→      sel.addRange(range);
   582→    } else {
   583→      el.appendChild(chip);
   584→    }
   585→    // Ensure a text node follows so typing continues naturally
   586→    const space = document.createTextNode('\u00A0');
   587→    chip.after(space);
   588→    const r = document.createRange();
   589→    r.setStart(space, 1);
   590→    r.collapse(true);
   591→    const s = window.getSelection();
   592→    s?.removeAllRanges();
   593→    s?.addRange(r);
