   595→    isInternalChangeRef.current = true;
   596→    onInputDraftChange(editablePlainText(el));
   597→    setHasContent(true);
   598→  };
   599→
   600→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   601→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   602→
   603→  const toggleRecording = () => {
   604→    if (isRecording) {
   605→      recognitionRef.current?.stop();
   606→      setIsRecording(false);
   607→      return;
   608→    }
   609→    const SpeechRecognitionAPI =
   610→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   611→    if (!SpeechRecognitionAPI) {
   612→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   613→      return;
   614→    }
   615→    const recognition = new SpeechRecognitionAPI();
   616→    recognition.continuous = true;
   617→    recognition.interimResults = true;
   618→    recognition.lang = 'en-US';
   619→    // Capture the base text at recording start; all mutations use this as ground truth
   620→    const startBase = editableRef.current ? editablePlainText(editableRef.current) : inputDraft;
   621→    let committedText = startBase;
   622→    recognition.onresult = (event: any) => {
   623→      let interim = '';
   624→      for (let i = event.resultIndex; i < event.results.length; i++) {
   625→        const t = event.results[i][0].transcript;
   626→        if (event.results[i].isFinal) {
   627→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   628→        } else {
   629→          interim = t;
   630→        }
   631→      }
   632→      if (interim) {
   633→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   634→      } else {
   635→        onInputDraftChange(committedText);
   636→      }
   637→    };
   638→    recognition.onend = () => {
   639→      setIsRecording(false);
   640→      onInputDraftChange(committedText);
   641→    };
   642→    recognition.onerror = () => {
   643→      setIsRecording(false);
   644→      onInputDraftChange(committedText);
   645→    };
   646→    recognitionRef.current = recognition;
   647→    recognition.start();
   648→    setIsRecording(true);
   649→  };
   650→
   651→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   652→    if (speakingIdx === idx) {
   653→      speechSynthesis.cancel();
   654→      setSpeakingIdx(null);
   655→      return;
   656→    }
   657→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   658→    if (!text.trim()) return;
   659→    speechSynthesis.cancel();
   660→    const utterance = new SpeechSynthesisUtterance(text);
   661→    utterance.onend = () => setSpeakingIdx(null);
   662→    utterance.onerror = () => setSpeakingIdx(null);
   663→    setSpeakingIdx(idx);
   664→    speechSynthesis.speak(utterance);
   665→  };
