   677→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   678→          </p>
   679→        </div>
   680→      </main>
   681→    );
   682→  }
   683→
   684→  return (
   685→    <main className="flex-1 flex flex-col min-w-0">
   686→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   687→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   688→        <button
   689→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
   690→            hideToolsAndThinking
   691→              ? 'bg-bg-active border-accent text-accent'
   692→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-text-bright'
   693→          }`}
   694→          onClick={() => setHideToolsAndThinking((v) => !v)}
   695→          title={hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   696→        >
