    61→        if (request.containsKey("providerId")) {
    62→            var rawProviderId = request.get("providerId");
    63→            providerId = (rawProviderId == null || rawProviderId.isBlank()) ? null : rawProviderId;
    64→        }
    65→        var botName = conversation.botName();
    66→        if (request.containsKey("botName")) {
    67→            var rawBot = request.get("botName");
    68→            if (rawBot == null || rawBot.isBlank() || "default".equalsIgnoreCase(rawBot)) {
    69→                botName = null;
