   127→
   128→  const handleSend = async (message: string, attachments?: FileAttachment[]) => {
   129→    if (!activeId) return;
   130→    inputDraftRef.current = '';
   131→    setDraftVersion((v) => v + 1);
   132→    if (pollIntervalRef.current) {
   133→      clearInterval(pollIntervalRef.current);
   134→      pollIntervalRef.current = null;
   135→    }
   136→    setLastStreamedContent(null);
   137→    const files = attachments ?? [];
   138→    setConversations((prev) =>
   139→      prev.map((c) =>
   140→        c.id === activeId
