   164→          // Tool finished (approved or rejected) — remove matching pending approval
   165→          setPendingApprovals((prev) => {
   166→            if (prev.length === 0) return prev;
   167→            // Remove the first pending entry whose toolName appears in the tool chunk content
   168→            const idx = prev.findIndex((p) => chunk.content.includes(p.toolName));
   169→            if (idx === -1) return prev;
   170→            return [...prev.slice(0, idx), ...prev.slice(idx + 1)];
   171→          });
   172→        }
   173→        setStreaming((prev) => {
   174→          if (!prev) return prev;
   175→          let next: StreamingContent;
   176→          if (chunk.type === 'reasoning') {
   177→            next = { ...prev, reasoning: prev.reasoning + chunk.content };
   178→          } else if (chunk.type === 'tool') {
   179→            next = { ...prev, parts: [...prev.parts, { type: 'tool', content: chunk.content }] };
   180→          } else {
   181→            const prevParts = prev.parts;
   182→            const last = prevParts[prevParts.length - 1];
   183→            if (last?.type === 'answer') {
   184→              next = {
   185→                ...prev,
   186→                parts: [...prevParts.slice(0, -1), { type: 'answer', content: last.content + chunk.content }],
   187→              };
   188→            } else {
   189→              next = { ...prev, parts: [...prevParts, { type: 'answer', content: chunk.content }] };
   190→            }
   191→          }
   192→          streamingRef.current = next;
   193→          return next;
   194→        });
   195→      },
   196→      () => {
   197→        const ref = streamingRef.current;
