   302→
   303→function parseStructuredContent(content: string): StreamPart[] | null {
   304→  if (!content || typeof content !== 'string') return null;
   305→  const trimmed = content.trim();
   306→  if (!trimmed.startsWith('{"parts":')) return null;
   307→  try {
   308→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   309→    if (!Array.isArray(data.parts)) return null;
   310→    const parts: StreamPart[] = data.parts
   311→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   312→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   313→    return parts.length > 0 ? parts : null;
   314→  } catch {
   315→    return null;
   316→  }
   317→}
   318→
   319→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   320→  if (!hideToolsAndThinking) return parts;
   321→  const answerParts = parts.filter((p) => p.type === 'answer');
   322→  return answerParts.map((p, i, arr) => ({
   323→    ...p,
   324→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   325→  }));
   326→}
   327→
   328→function getDisplayMessages(
   329→  messages: ChatMessage[],
   330→  hideToolsAndThinking: boolean,
   331→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   332→): DisplayMessage[] {
   333→  let list: DisplayMessage[] = messages.map((msg) => {
   334→    if (msg.role === 'assistant') {
   335→      const parts = parseStructuredContent(msg.content);
   336→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   337→    }
   338→    return msg;
   339→  });
   340→  if (lastStreamedContent && list.length > 0) {
   341→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   342→    const afterLastUser = list.slice(lastUserIdx + 1);
   343→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   344→      const parts: StreamPart[] = lastStreamedContent.reasoning
   345→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   346→        : lastStreamedContent.parts;
   347→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   348→    }
   349→  }
   350→  return list;
   351→}
   352→
   353→// CSS class applied to inline file chips inside the contentEditable input div.
   354→// Must match classes used in JSX FileChip to survive Tailwind tree-shaking.
   355→const FILE_CHIP_CLASS =
   356→  'inline-flex items-center gap-1 py-0.5 pl-1.5 pr-1 rounded border border-border bg-bg-input text-text-dim text-xs mx-0.5 align-middle select-none';
   357→
   358→function editablePlainText(el: HTMLDivElement): string {
   359→  let text = '';
   360→  el.childNodes.forEach((n) => {
   361→    if (n.nodeType === Node.TEXT_NODE) text += n.textContent ?? '';
   362→  });
   363→  return text;
   364→}
   365→
   366→function editableHasContent(el: HTMLDivElement): boolean {
   367→  if (editablePlainText(el).trim()) return true;
   368→  return Array.from(el.childNodes).some(
   369→    (n) => n.nodeType === Node.ELEMENT_NODE && !!(n as HTMLElement).dataset.fileId
   370→  );
   371→}
   372→
   373→type UserPart = { type: 'text'; content: string } | { type: 'file'; id: string; name: string; mimeType: string };
   374→
   375→function parseUserParts(content: string): UserPart[] | null {
   376→  if (!content || !content.trim().startsWith('{"user_parts":')) return null;
   377→  try {
   378→    const data = JSON.parse(content) as { user_parts?: Array<{ type: string; content?: string; id?: string; name?: string; mimeType?: string }> };
   379→    if (!Array.isArray(data.user_parts)) return null;
   380→    return data.user_parts
   381→      .filter((p) => p.type === 'text' || p.type === 'file')
   382→      .map((p) =>
   383→        p.type === 'file'
   384→          ? { type: 'file' as const, id: p.id ?? '', name: p.name ?? '', mimeType: p.mimeType ?? '' }
   385→          : { type: 'text' as const, content: p.content ?? '' }
   386→      );
   387→  } catch {
   388→    return null;
   389→  }
   390→}
   391→
   392→function extractEditableContent(el?: HTMLDivElement | null): { parts: UserPart[]; files: FileAttachment[] } {
   393→  if (!el) return { parts: [], files: [] };
   394→  const rawParts: UserPart[] = [];
   395→  const files: FileAttachment[] = [];
   396→  el.childNodes.forEach((n) => {
   397→    if (n.nodeType === Node.TEXT_NODE) {
   398→      const text = n.textContent ?? '';
   399→      if (text) {
   400→        const last = rawParts[rawParts.length - 1];
   401→        if (last?.type === 'text') {
   402→          (last as { type: 'text'; content: string }).content += text;
   403→        } else {
   404→          rawParts.push({ type: 'text', content: text });
   405→        }
   406→      }
   407→    } else if (n.nodeType === Node.ELEMENT_NODE) {
   408→      const span = n as HTMLElement;
   409→      if (span.dataset.fileId) {
   410→        const file: FileAttachment = { id: span.dataset.fileId, name: span.dataset.fileName ?? '', mimeType: span.dataset.fileMimeType ?? '' };
   411→        rawParts.push({ type: 'file', id: file.id, name: file.name, mimeType: file.mimeType });
   412→        files.push(file);
   413→      }
   414→    }
   415→  });
   416→  // Trim leading/trailing whitespace from boundary text parts
   417→  if (rawParts.length > 0 && rawParts[0].type === 'text') {
   418→    (rawParts[0] as { type: 'text'; content: string }).content = (rawParts[0] as { type: 'text'; content: string }).content.trimStart();
   419→  }
   420→  const lastPart = rawParts[rawParts.length - 1];
   421→  if (lastPart?.type === 'text') {
   422→    (lastPart as { type: 'text'; content: string }).content = (lastPart as { type: 'text'; content: string }).content.trimEnd();
   423→  }
   424→  const parts = rawParts.filter((p) => p.type === 'file' || (p as { type: 'text'; content: string }).content.length > 0);
   425→  return { parts, files };
   426→}
   427→
   428→function escapeHtml(s: string): string {
   429→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
   430→}
   431→
   432→export default function ChatWindow({
   433→  headerTitle,
   434→  conversation,
   435→  providers,
   436→  bots,
   437→  sending,
   438→  streaming,
   439→  lastStreamedContent,
   440→  inputDraft,
   441→  onInputDraftChange,
   442→  onSend,
   443→  onUpdateProvider,
   444→  onUpdateBot,
   445→  pendingApprovals,
   446→  onApproveTool,
   447→  onRejectTool,
   448→}: ChatWindowProps) {
   449→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   450→  const [isRecording, setIsRecording] = useState(false);
   451→  const [speakingIdx, setSpeakingIdx] = useState<number | null>(null);
   452→  const [uploadingFile, setUploadingFile] = useState(false);
   453→  const [hasContent, setHasContent] = useState(false);
   454→  const messagesRef = useRef<HTMLDivElement>(null);
   455→  const topRef = useRef<HTMLDivElement>(null);
   456→  const bottomRef = useRef<HTMLDivElement>(null);
   457→  const recognitionRef = useRef<any>(null);
   458→  const fileInputRef = useRef<HTMLInputElement>(null);
   459→  const editableRef = useRef<HTMLDivElement>(null);
   460→  // true while we are the source of an inputDraft change — prevents syncing back
   461→  const isInternalChangeRef = useRef(false);
   462→
   463→  // Stop recording and TTS when conversation changes
   464→  useEffect(() => {
   465→    recognitionRef.current?.stop();
   466→    setIsRecording(false);
   467→    speechSynthesis.cancel();
   468→    setSpeakingIdx(null);
   469→  }, [conversation?.id]);
   470→
   471→  // Sync external inputDraft changes (e.g. speech recognition) into the editable div
   472→  // while preserving file chips already embedded in the div.
   473→  useLayoutEffect(() => {
   474→    if (isInternalChangeRef.current) {
   475→      isInternalChangeRef.current = false;
   476→      return;
   477→    }
   478→    const el = editableRef.current;
   479→    if (!el) return;
   480→    // Collect existing chip nodes to re-append after text
   481→    const chips = Array.from(el.childNodes).filter(
   482→      (n) => n.nodeType === Node.ELEMENT_NODE && (n as HTMLElement).dataset.fileId
   483→    );
   484→    el.innerHTML = '';
   485→    if (inputDraft) el.appendChild(document.createTextNode(inputDraft));
   486→    chips.forEach((c) => el.appendChild(c));
   487→    setHasContent(editableHasContent(el));
   488→  }, [inputDraft]);
   489→
   490→  const visibleMessages = conversation
   491→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   492→    : [];
   493→
   494→  useEffect(() => {
   495→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   496→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   497→
   498→  const hasProvider = Boolean(conversation?.providerId);
   499→  const isDirectChat = Boolean(
   500→    conversation?.participant1 != null && conversation?.participant2 != null
   501→  );
   502→
   503→  const handleSend = () => {
   504→    if (sending || !hasProvider) return;
   505→    const { parts, files } = extractEditableContent(editableRef.current);
   506→    if (parts.length === 0) return;
   507→    const el = editableRef.current;
   508→    if (el) {
   509→      el.innerHTML = '';
   510→      isInternalChangeRef.current = true;
   511→      onInputDraftChange('');
   512→      setHasContent(false);
   513→    }
   514→    const message = files.length > 0
   515→      ? JSON.stringify({ user_parts: parts })
   516→      : ((parts[0] as { type: 'text'; content: string })?.content ?? '');
   517→    onSend(message, files.length > 0 ? files : undefined);
   518→  };
   519→
   520→  const handleEditableInput = () => {
   521→    const el = editableRef.current;
   522→    if (!el) return;
   523→    isInternalChangeRef.current = true;
   524→    onInputDraftChange(editablePlainText(el));
   525→    setHasContent(editableHasContent(el));
   526→  };
   527→
   528→  const handleEditableClick = (e: React.MouseEvent<HTMLDivElement>) => {
   529→    const target = e.target as HTMLElement;
   530→    if (target.dataset.removeChipId) {
   531→      const chip = target.closest('[data-file-id]') as HTMLElement | null;
   532→      chip?.remove();
   533→      isInternalChangeRef.current = true;
   534→      const el = editableRef.current;
   535→      if (el) {
   536→        onInputDraftChange(editablePlainText(el));
   537→        setHasContent(editableHasContent(el));
   538→      }
   539→    }
   540→  };
   541→
   542→  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
   543→    const files = Array.from(e.target.files ?? []);
   544→    if (files.length === 0) return;
   545→    e.target.value = '';
   546→    setUploadingFile(true);
   547→    try {
   548→      const uploaded = await Promise.all(files.map((f) => api.uploadFile(conversation!.id, f)));
   549→      uploaded.forEach(insertFileChip);
   550→    } catch {
   551→      // ignore upload errors silently
   552→    } finally {
   553→      setUploadingFile(false);
   554→    }
   555→  };
   556→
   557→  const insertFileChip = (attachment: FileAttachment) => {
   558→    const el = editableRef.current;
   559→    if (!el) return;
   560→    el.focus();
   561→    const chip = document.createElement('span');
   562→    chip.contentEditable = 'false';
   563→    chip.dataset.fileId = attachment.id;
   564→    chip.dataset.fileName = attachment.name;
   565→    chip.dataset.fileMimeType = attachment.mimeType;
   566→    chip.className = FILE_CHIP_CLASS;
   567→    chip.title = attachment.name;
   568→    chip.innerHTML =
   569→      `<svg width="11" height="11" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0"><path d="M7 1H3a1 1 0 00-1 1v8a1 1 0 001 1h6a1 1 0 001-1V4L7 1z"/><path d="M7 1v3h3"/></svg>` +
   570→      `<span style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(attachment.name)}</span>` +
   571→      `<span data-remove-chip-id="${attachment.id}" style="cursor:pointer;margin-left:2px;opacity:0.7;flex-shrink:0" title="Remove">✕</span>`;
   572→
   573→    const sel = window.getSelection();
   574→    if (sel && sel.rangeCount > 0 && el.contains(sel.getRangeAt(0).commonAncestorContainer)) {
   575→      const range = sel.getRangeAt(0);
   576→      range.deleteContents();
   577→      range.insertNode(chip);
   578→      range.setStartAfter(chip);
   579→      range.collapse(true);
   580→      sel.removeAllRanges();
   581→      sel.addRange(range);
   582→    } else {
   583→      el.appendChild(chip);
   584→    }
   585→    // Ensure a text node follows so typing continues naturally
   586→    const space = document.createTextNode('\u00A0');
   587→    chip.after(space);
   588→    const r = document.createRange();
   589→    r.setStart(space, 1);
   590→    r.collapse(true);
   591→    const s = window.getSelection();
   592→    s?.removeAllRanges();
   593→    s?.addRange(r);
   594→
   595→    isInternalChangeRef.current = true;
   596→    onInputDraftChange(editablePlainText(el));
   597→    setHasContent(true);
   598→  };
   599→
   600→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   601→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   602→
   603→  const toggleRecording = () => {
   604→    if (isRecording) {
   605→      recognitionRef.current?.stop();
   606→      setIsRecording(false);
   607→      return;
   608→    }
   609→    const SpeechRecognitionAPI =
   610→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   611→    if (!SpeechRecognitionAPI) {
   612→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   613→      return;
   614→    }
   615→    const recognition = new SpeechRecognitionAPI();
   616→    recognition.continuous = true;
   617→    recognition.interimResults = true;
   618→    recognition.lang = 'en-US';
   619→    // Capture the base text at recording start; all mutations use this as ground truth
   620→    const startBase = editableRef.current ? editablePlainText(editableRef.current) : inputDraft;
   621→    let committedText = startBase;
   622→    recognition.onresult = (event: any) => {
   623→      let interim = '';
   624→      for (let i = event.resultIndex; i < event.results.length; i++) {
   625→        const t = event.results[i][0].transcript;
   626→        if (event.results[i].isFinal) {
   627→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   628→        } else {
   629→          interim = t;
   630→        }
   631→      }
   632→      if (interim) {
   633→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   634→      } else {
   635→        onInputDraftChange(committedText);
   636→      }
   637→    };
   638→    recognition.onend = () => {
   639→      setIsRecording(false);
   640→      onInputDraftChange(committedText);
   641→    };
   642→    recognition.onerror = () => {
   643→      setIsRecording(false);
   644→      onInputDraftChange(committedText);
   645→    };
   646→    recognitionRef.current = recognition;
   647→    recognition.start();
   648→    setIsRecording(true);
   649→  };
   650→
   651→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   652→    if (speakingIdx === idx) {
   653→      speechSynthesis.cancel();
   654→      setSpeakingIdx(null);
   655→      return;
   656→    }
   657→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   658→    if (!text.trim()) return;
   659→    speechSynthesis.cancel();
   660→    const utterance = new SpeechSynthesisUtterance(text);
   661→    utterance.onend = () => setSpeakingIdx(null);
   662→    utterance.onerror = () => setSpeakingIdx(null);
   663→    setSpeakingIdx(idx);
   664→    speechSynthesis.speak(utterance);
   665→  };
   666→
   667→  if (!conversation) {
   668→    return (
   669→      <main className="flex-1 flex flex-col min-w-0">
   670→        <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   671→          <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   672→        </header>
   673→        <div className="flex-1 flex items-center justify-center text-text-dim text-base">
   674→          <p>
   675→            {headerTitle === 'User'
   676→              ? 'Select or create a conversation to start chatting'
   677→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   678→          </p>
   679→        </div>
   680→      </main>
   681→    );
   682→  }
   683→
   684→  return (
   685→    <main className="flex-1 flex flex-col min-w-0">
   686→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   687→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   688→        <button
   689→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
   690→            hideToolsAndThinking
   691→              ? 'bg-bg-active border-accent text-accent'
   692→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-text-bright'
   693→          }`}
   694→          onClick={() => setHideToolsAndThinking((v) => !v)}
   695→          title={hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   696→        >
   697→          {hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   698→        </button>
   699→      </header>
   700→
   701→      <div className="flex-1 overflow-y-auto py-4 px-5 flex flex-col gap-3" ref={messagesRef}>
   702→        <div ref={topRef} />
   703→        {visibleMessages.map((msg, i) => (
   704→          <MessageEntry
   705→            key={i}
   706→            msg={msg}
   707→            conversation={conversation}
   708→            speaking={speakingIdx === i}
   709→            onSpeak={() => speakMessage(msg, i)}
   710→          />
   711→        ))}
   712→        {sending && (() => {
   713→          const assistantLabel = roleDisplayName('assistant', conversation);
   714→          return (
   715→          <div className="max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed self-start bg-assistant-bg border border-border opacity-95">
   716→            <div className="flex items-baseline gap-2 cursor-pointer select-none">
   717→              <span className={`text-[0.6875rem] font-semibold tracking-wide text-text-dim shrink-0 ${['user', 'assistant', 'tool'].includes(assistantLabel.toLowerCase()) ? 'uppercase' : ''}`}>
   718→                {assistantLabel}
   719→              </span>
   720→            </div>
   721→            <div className="text-text-bright mt-1.5 min-w-0 break-words">
   722→              {streaming?.reasoning ? (
   723→                <details className="mb-2" open>
   724→                  <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
   725→                    Thinking
   726→                  </summary>
   727→                  <pre className="mt-1.5 p-2 bg-bg rounded-lg text-xs text-text-dim whitespace-pre-wrap break-words max-h-[200px] overflow-y-auto">
   728→                    {streaming.reasoning}
   729→                  </pre>
   730→                </details>
   731→              ) : null}
   732→              {streaming?.reasoning && streaming.parts.length > 0 ? (
   733→                <div className="h-px bg-border my-2" />
   734→              ) : null}
   735→              {streaming?.parts.map((part, i) =>
   736→                part.type === 'tool' ? (
   737→                  <details key={i} className="message-tool-part my-2 py-2 px-2.5 bg-tool-bg border border-tool-border rounded-lg text-tool-text max-w-full overflow-hidden" open>
   738→                    <summary className="flex items-center gap-2 cursor-pointer text-xs font-semibold uppercase text-tool-summary list-none [&::-webkit-details-marker]:hidden [&::marker]:hidden">
   739→                      <span>Tool</span>
   740→                      <span className="btn-msg-toggle flex items-center justify-center w-6 h-6 ml-auto shrink-0 rounded-md border border-tool-border bg-tool-bg/80 text-[0.65rem] font-medium leading-none transition-all duration-150 hover:border-tool-summary hover:opacity-90" />
   741→                    </summary>
   742→                    <pre className="mt-1.5 font-mono text-xs text-tool-text whitespace-pre-wrap break-words max-w-full overflow-x-auto overflow-y-hidden">
   743→                      {part.content}
   744→                    </pre>
   745→                  </details>
   746→                ) : (
   747→                  <span key={i} className="whitespace-pre-wrap break-words">{part.content}</span>
   748→                )
   749→              )}
   750→              {streaming && streaming.parts.length === 0 && !streaming.reasoning && (
   751→                <span className="whitespace-pre-wrap break-words">Thinking…</span>
   752→              )}
   753→            </div>
   754→          </div>
   755→          );
   756→        })()}
   757→        {pendingApprovals.map((approval) => (
   758→          <ToolApprovalCard
   759→            key={approval.approvalId}
   760→            approval={approval}
   761→            onApprove={() => onApproveTool(approval.approvalId)}
   762→            onReject={() => onRejectTool(approval.approvalId)}
   763→          />
   764→        ))}
   765→        <div ref={bottomRef} />
   766→      </div>
   767→
   768→      <div className="flex items-end gap-2 py-3 px-5 border-t border-border bg-bg-sidebar">
   769→        <div className="flex flex-col gap-1">
   770→          <button
   771→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0 disabled:opacity-50 disabled:cursor-not-allowed"
   772→            onClick={scrollToTop}
   773→            title="Scroll to top"
   774→          >
   775→            ▲
   776→          </button>
   777→          <button
   778→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0"
   779→            onClick={scrollToBottom}
   780→            title="Scroll to bottom"
   781→          >
   782→            ▼
   783→          </button>
   784→        </div>
   785→        <div
   786→          ref={editableRef}
   787→          contentEditable={sending || !hasProvider ? 'false' : 'true'}
   788→          suppressContentEditableWarning
   789→          onInput={handleEditableInput}
   790→          onClick={handleEditableClick}
   791→          onKeyDown={(e) => {
   792→            if (e.key === 'Enter' && !e.shiftKey) {
   793→              e.preventDefault();
   794→              handleSend();
   795→            }
   796→          }}
   797→          data-placeholder="Type a message… (Enter to send, Shift+Enter for newline)"
   798→          className={`flex-1 min-h-[3rem] max-h-40 overflow-y-auto py-2.5 px-3.5 bg-bg-input text-text border border-border rounded-lg text-sm leading-normal outline-none focus:border-accent empty:before:content-[attr(data-placeholder)] empty:before:text-text-dim ${sending || !hasProvider ? 'opacity-50 cursor-not-allowed' : ''}`}
   799→        />
   800→        <input
   801→          ref={fileInputRef}
   802→          type="file"
   803→          multiple
   804→          className="hidden"
   805→          onChange={handleFileSelect}
   806→        />
   807→        <button
   808→          className={`w-9 h-9 flex items-center justify-center rounded-lg border cursor-pointer transition-all duration-150 shrink-0 ${
   809→            isRecording
   810→              ? 'bg-danger/20 border-danger text-danger animate-pulse'
   811→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-accent hover:bg-bg-hover'
   812→          } disabled:opacity-40 disabled:cursor-not-allowed`}
   813→          onClick={toggleRecording}
   814→          disabled={sending || !hasProvider}
   815→          title={isRecording ? 'Stop recording' : 'Speak (voice input)'}
   816→        >
   817→          <MicIcon />
   818→        </button>
   819→        <button
   820→          className="w-9 h-9 flex items-center justify-center rounded-lg border cursor-pointer transition-all duration-150 shrink-0 bg-bg-input text-text-dim border-border hover:border-accent hover:text-accent hover:bg-bg-hover disabled:opacity-40 disabled:cursor-not-allowed"
   821→          onClick={() => fileInputRef.current?.click()}
   822→          disabled={sending || !hasProvider || uploadingFile}
   823→          title="Attach files"
   824→        >
   825→          <PaperclipIcon />
   826→        </button>
   827→        <div className="flex flex-col gap-1 items-end shrink-0">
   828→          <select
   829→            value={conversation.providerId ?? ''}
   830→            onChange={(e) => onUpdateProvider(conversation.id, e.target.value || null)}
   831→            className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   832→          >
   833→            <option value="">Select agent…</option>
   834→            {providers.map((p) => (
   835→              <option key={p.id} value={p.id}>{p.name}</option>
   836→            ))}
   837→          </select>
   838→          {!isDirectChat && (
   839→            <select
   840→              value={conversation.botName ?? 'default'}
   841→              onChange={(e) => onUpdateBot(conversation.id, e.target.value === 'default' ? null : e.target.value)}
   842→              className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   843→            >
   844→              <option value="default">default</option>
   845→              {bots.map((b) => (
   846→                <option key={b.name} value={b.name}>{b.name}</option>
   847→              ))}
   848→            </select>
   849→          )}
   850→          {!hasProvider && (
   851→            <span className="text-[0.6875rem] text-text-dim">Select agent to send</span>
   852→          )}
   853→          <button
   854→            className="py-2.5 px-5 bg-accent text-white border-0 rounded-lg cursor-pointer text-sm font-medium transition-colors duration-150 w-full hover:bg-accent-hover disabled:opacity-40 disabled:cursor-not-allowed"
   855→            onClick={handleSend}
   856→            disabled={sending || !hasProvider || !hasContent}
   857→          >
   858→            Send
   859→          </button>
   860→        </div>
   861→      </div>
   862→    </main>
   863→  );
   864→}
