          </button>
        </div>
      )}
      {providers.length > 0 && (
        <div className="flex flex-wrap gap-1 mt-2">
          {providers.map((p) => (
            <span key={p.id} className="text-xs text-text-dim bg-bg-input py-0.5 px-2 rounded-xl">
              {p.name} ({p.model})
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

function BotButton({
  show,
  onToggle,
